class Solution:
    def maxDiff(self, num):
        """
        :type num: int
        :rtype: int
        """
        s = str(num)

        # Maximize: find first digit != 9 from left, replace with 9
        max_str = list(s)
        for i in range(len(max_str)):
            if max_str[i] != '9':
                digit = max_str[i]
                for j in range(len(max_str)):
                    if max_str[j] == digit:
                        max_str[j] = '9'
                break

        # Minimize: find first digit != 0 and != 1 from left, replace with 1
        # Special case: first digit can't be 0, so replace with 1
        min_str = list(s)
        for i in range(len(min_str)):
            if i == 0:
                # First digit: replace with 1 if not 1
                if min_str[i] != '1':
                    digit = min_str[i]
                    for j in range(len(min_str)):
                        if min_str[j] == digit:
                            min_str[j] = '1'
                    break
            else:
                # Other digits: replace with 0 if not 0 and not 1
                if min_str[i] != '0' and min_str[i] != '1':
                    digit = min_str[i]
                    for j in range(i, len(min_str)):
                        if min_str[j] == digit:
                            min_str[j] = '0'
                    break

        return int(''.join(max_str)) - int(''.join(min_str))
